void FeatureSpy260721::GetInfomation()
{
	std::vector<Face*> HorizontalFaceVector;

	//гУforЗНЪНЯТБъБщРњvectorЪЧзюПьЕФЃЌЕќДњЦїiteratorЪЧзюТ§ЕФ
	for (std::vector<Face*>::size_type i = 0; i != AllFaces.size(); i++)
	{
		Face* EachFace = AllFaces[i];

		//бЁГіЫљгаЫЎЦНУц
		if (EachFace->SolidFaceType() == Face::FaceTypePlanar)
		{
			Vector3d EachMainNormal;
			get_MainNormal_fr_plane(EachFace, EachMainNormal);
			double angle = get_Angle_Two_vector3d(EachMainNormal, _Approach_Normal);//ЛёШЁСНИіЦНУцЕФЗЈЯђМаНЧ

			angle = angle / PI * 180;
			if (angle < 0.01 || angle > 179.99) HorizontalFaceVector.push_back(EachFace);
		}
	}

	//евГіСНЖЫУцЃЌМДЕзУцЃЈзюЕЭУцЃЉКЭЖЅУцЃЈзюИпУцЃЉ
	int TopPlaneIndex = -1;
	int BottomPlaneIndex = -1;
	double ZMax = 1000000;
	double ZMin = -1000000;

	for (std::vector<Face*>::size_type i = 0; i != HorizontalFaceVector.size(); i++)
	{
		Face* EachFace = HorizontalFaceVector[i];
		Point3d FaceCenterPoint;
		NXOpen::Vector3d FaceCenterNormal;
		get_Centre_fr_Face(EachFace, FaceCenterPoint, FaceCenterNormal);
		double _name_Z = 0;

		if (_Approach_Normal.X == 0 && _Approach_Normal.Y == 0 && _Approach_Normal.Z == 1)
		{
			_name_Z = FaceCenterPoint.Z;
		}
		else if (_Approach_Normal.X == 0 && _Approach_Normal.Y == 1 && _Approach_Normal.Z == 0)
		{
			_name_Z = FaceCenterPoint.Y;
		}
		else if (_Approach_Normal.X == 1 && _Approach_Normal.Y == 0 && _Approach_Normal.Z == 0)
		{
			_name_Z = FaceCenterPoint.X;
		}
		else
		{
			//uc1601(" WarningЃЁ\n НЈФЃа§зЊжсЗЧXYZШ§зјБъжсжЎвЛ",1);
			_name_Z = FaceCenterPoint.X*_Approach_Normal.X + FaceCenterPoint.Y*_Approach_Normal.Y + FaceCenterPoint.Z*_Approach_Normal.Z;
		}


		if (_name_Z < ZMax)
		{
			ZMax = _name_Z;
			BottomPlaneIndex = i;
		}

		if (_name_Z > ZMin)
		{
			ZMin = _name_Z;
			TopPlaneIndex = i;
		}
	}

	if (TopPlaneIndex == -1 || BottomPlaneIndex == -1 || TopPlaneIndex == BottomPlaneIndex)
	{
		uc1601(" ErrorЃЁ\n ФЃаЭЩЯЯТЖЫУцВЛШЋЮЊЦНУцЛђЗжаЭУцбЁдёДэЮѓЃЁ", 1);
		std::vector<Face*> AllF;
		Face* errorface = AllF[-1];
		//return;
	}
	BottomPlaneFace = (Face*)HorizontalFaceVector[BottomPlaneIndex];
	TopPlaneFace = (Face*)HorizontalFaceVector[TopPlaneIndex];

	for (std::vector<Face*>::size_type i = 0; i != HorizontalFaceVector.size(); i++)
	{
		Face* EachFace = HorizontalFaceVector[i];
		////СНИіЯђСПЕФНЧЖШ гыЖЅЕзУцЦНааЕФУц
		Point3d FaceCenterPoint, facepoint1;
		NXOpen::Vector3d FaceCenterNormal, facenorm1;
		get_Centre_fr_Face(TopPlaneFace, FaceCenterPoint, FaceCenterNormal);

		get_Centre_fr_Face(EachFace, facepoint1, facenorm1);
		double Vec1[3] = { FaceCenterPoint.X - facepoint1.X, FaceCenterPoint.Y - facepoint1.Y, FaceCenterPoint.Z - facepoint1.Z };


		int _type1;
		double _point1[3];
		double _dir1[3];
		double _box1[6];
		double _radius1;
		double _rad_data1;
		int _norm_dir1;

		UF_MODL_ask_face_data(TopPlaneFace->Tag(), &_type1, _point1, _dir1,
			_box1, &_radius1, &_rad_data1, &_norm_dir1);
		double Vec2[3] = { _dir1[0], _dir1[1], _dir1[2] };
		//ЧѓСНИіЯђСПЕФВцГЫ
		double CrossProduct[3];
		UF_VEC3_cross(Vec1, Vec2, CrossProduct);

		//вбжЊСНИіЯђСПЧѓМаНЧ(ЪфГіЕФЪЧЛЁЖШ)
		double Angle;
		UF_VEC3_angle_between(Vec1, Vec2, CrossProduct, &Angle);
		double angle = Angle / PI * 180;
		if (angle < 1 || angle >179)
		{
			if (EachFace->Tag() != TopPlaneFace->Tag() && EachFace->Tag() != BottomPlaneFace->Tag())
			{
				//UF_OBJ_set_color(EachFace->Tag(),186);
				ParallelPlaneFace.push_back(EachFace);

			}

		}
	}

}

